import React from 'react';

const isSSR = () => typeof window === 'undefined';

/** @type {typeof import('../..').withTracker<any>} */
const withTracker = (WrappedComponent, metrics = {}) => {
  class TrackerHOC extends React.PureComponent {
    /** @param {typeof import('../..').WithTrackerProps} props */
    constructor(props) {
      super(props);

      if (isSSR()) {
        if ('SSR' in metrics && Array.isArray(metrics.SSR)) {
          metrics.SSR.forEach(/** @type {() => void} */ (track) => {
            if (typeof track === 'function') track(props);
          });
        }
      }
    }

    render() {
      const { forwardedRef } = this.props;

      return <WrappedComponent {...this.props} ref={forwardedRef} />;
    }
  }

  TrackerHOC.propTypes = {
    ...WrappedComponent.propTypes,
  };

  // @ts-expect-error ref could be of any type
  const Component = ({ ref, ...props }) => <TrackerHOC {...props} forwardedRef={ref} />;

  Component.displayName = WrappedComponent.displayName;

  return Component;
};

export default withTracker;
